function debounce(fn, delay){
  let timer;
  return (...args)=>{
    clearTimeout(timer);
    timer = setTimeout(()=>fn(...args), delay);
  };
}

function throttle(fn, delay){
  let waiting = false;
  return (...args)=>{
    if(waiting) return;
    waiting = true;
    fn(...args);
    setTimeout(()=>waiting = false, delay);
  };
}

